@@ -40,6 +40,8 @@ pub const PyValue = union(enum) {
         gt: ?*const fn (*anyopaque, PyValue) PyValue = null,
         /// __ge__ method: greater than or equal comparison
         ge: ?*const fn (*anyopaque, PyValue) PyValue = null,
+        /// __call__ method: callable protocol
+        __call__: ?*const fn (*anyopaque, []const PyValue) anyerror!PyValue = null,
     };

     /// Class instance with vtable for dynamic method dispatch
@@ -121,6 +123,17 @@ pub const PyValue = union(enum) {
             vtable.ge = GeWrapper.call;
         }

+        // Generate __call__ wrapper if the type has it
+        if (@hasDecl(T, "__call__")) {
+            const CallWrapper = struct {
+                fn call(ptr: *anyopaque, args: []const PyValue) anyerror!PyValue {
+                    const self: *T = @ptrCast(@alignCast(ptr));
+                    return self.__call__(args);
+                }
+            };
+            vtable.__call__ = CallWrapper.call;
+        }
+
         return vtable;
     }

@@ -1049,6 +1062,21 @@ pub const PyValue = union(enum) {
         };
     }

+    /// Call a PyValue (callable protocol via __call__ dunder method)
+    /// Returns error if the value is not callable
+    pub fn call(self: PyValue, args: []const PyValue) !PyValue {
+        return switch (self) {
+            .object => |obj| {
+                if (obj.vtable.__call__) |call_fn| {
+                    return try call_fn(obj.ptr, args);
+                }
+                // Fallback: not callable
+                @panic("PyValue object is not callable (no __call__ method)");
+            },
+            else => @panic("PyValue is not callable"),
+        };
+    }
+
     /// Try to call a dunder method on an object instance
     /// Returns null if the method doesn't exist, or the PyValue result if it does
     /// Uses vtable for dynamic dispatch

@@ -740,17 +740,25 @@ pub fn genCall(self: *NativeCodegen, call: ast.Node.Call) CodegenError!void {
             }

             // Check if this is calling a PyValue attribute (e.g., self.logger where logger is PyValue)
-            // PyValue attributes cannot be called directly - they need special handling
-            // For now, emit a compile error with helpful message
+            // Generate runtime call() dispatch for PyValue callables
             if (!is_module_call and !is_class_method_call and !is_nested_class_method_call) {
                 // Try to infer the attribute type
                 const attr_type = self.type_inferrer.inferExpr(call.func.*) catch .unknown;
                 if (attr_type == .pyvalue) {
-                    // This is calling a PyValue - emit compile error for now
-                    // TODO: Add runtime support for calling PyValue callables
-                    try emitFmtConst(self, "@compileError(\"Cannot call PyValue attribute '{s}'. ", .{attr.attr});
-                    try emitConst(self, "Callable attributes stored as PyValue are not yet supported. ");
-                    try emitConst(self, "This is a known limitation in test_binop.py with logger callable.\")");
+                    // Generate PyValue.call() dispatch
+                    try emitConst(self, "(try ");
+                    try genExpr(self, call.func.*); // The PyValue attribute
+                    try emitConst(self, ".call(&[_]runtime.PyValue{");
+
+                    // Generate arguments
+                    for (call.args, 0..) |arg, i| {
+                        if (i > 0) try emitConst(self, ", ");
+                        try emitConst(self, "runtime.PyValue.from(");
+                        try genExpr(self, arg);
+                        try emitConst(self, ")");
+                    }
+
+                    try emitConst(self, "}))");
                     return;
                 }
             }
